          ]
        }
      ]
    }
  ],
  "resources": [
    {
      "kp_hint": "最短路径问题",
      "resource_kind": "method",
      "title": "最短路径问题的组合数计算方法",
      "content": "如图，从A到B的最短路径条数为：\n①横看：从$m+n$步中选出$m$步“向右”走，即从A到B的最短路径为$C_{m+n}^m$条！\n②竖看：从$m+n$步中选出$n$步“向上”走，即从A到B的最短路径为$C_{m+n}^n$条！",
      "figures": [
        {
          "figure_no": 1,
          "alt": "m×n网格最短路径示意图",
          "bbox": [
            0.58,
            0.25,
